def predict_next_frame(frame, action, xy=None):
    """
    Predict the next frame for the 64×64 grid game.

    The observed rules are:
      * ACTION6(x,y): toggle a 5×5 square centred on (x,y) between 0 and 4.
      * ACTION5: in row 53 (zero‑based) change the first cell with value 2
        (searching from column 1 onward) to 3.

    All other actions leave the board unchanged.
    """
    # Make a deep copy of the frame so we never modify the input.
    new_frame = [row[:] for row in frame]

    if action == "ACTION6" and xy is not None:
        x, y = xy
        for dy in range(-2, 3):
            ry = y + dy
            if 0 <= ry < 64:
                for dx in range(-2, 3):
                    cx = x + dx
                    if 0 <= cx < 64:
                        v = new_frame[ry][cx]
                        if v == 0:
                            new_frame[ry][cx] = 4
                        elif v == 4:
                            new_frame[ry][cx] = 0

    elif action == "ACTION5":
        target_row = 53
        # Scan columns starting at 1 (column 0 is never the first 2 to change)
        for col in range(1, 64):
            if new_frame[target_row][col] == 2:
                new_frame[target_row][col] = 3
                break

    return new_frame

